__kernel void compute_distances(
    __global const char* sandbox,
    const int rec_length,
    const int latitude_pos,
    const int rec_count,
    const float target_lat,
    const float target_long,
    __global float* z)
{
    int i = get_global_id(0);
    if(i < rec_count) {
        int base_idx = i * rec_length + latitude_pos - 1;
        // Ensure we do not read out of bounds
        if(base_idx + 9 >= rec_count * rec_length) {
            // Out of bounds, set distance to a large value
            z[i] = 1e20f;
            return;
        }

        // Extract latitude string (5 chars)
        char lat_str[6];
        for(int c = 0; c < 5; c++) {
            lat_str[c] = sandbox[base_idx + c];
        }
        lat_str[5] = '\0';

        // Extract longitude string (5 chars)
        char long_str[6];
        for(int c = 0; c < 5; c++) {
            long_str[c] = sandbox[base_idx + 5 + c];
        }
        long_str[5] = '\0';

        float tmp_lat = 0.0f;
        float tmp_long = 0.0f;

        // Convert strings to float
        // OpenCL does not have atof, so implement simple conversion
        // Here we assume the format is fixed and simple, so we parse manually

        // Simple atof implementation for 5-char strings (e.g. " 12.3")
        // Skip leading spaces
        int idx = 0;
        while(idx < 5 && (lat_str[idx] == ' ' || lat_str[idx] == '\t')) idx++;
        // Parse sign
        int sign = 1;
        if(idx < 5 && lat_str[idx] == '-') {
            sign = -1;
            idx++;
        }
        float val = 0.0f;
        int decimal_seen = 0;
        float decimal_factor = 0.1f;
        for(; idx < 5; idx++) {
            char ch = lat_str[idx];
            if(ch >= '0' && ch <= '9') {
                if(decimal_seen == 0) {
                    val = val * 10.0f + (ch - '0');
                } else {
                    val = val + (ch - '0') * decimal_factor;
                    decimal_factor *= 0.1f;
                }
            } else if(ch == '.') {
                decimal_seen = 1;
            } else {
                // ignore other chars
            }
        }
        tmp_lat = sign * val;

        // Repeat for longitude
        idx = 0;
        while(idx < 5 && (long_str[idx] == ' ' || long_str[idx] == '\t')) idx++;
        sign = 1;
        if(idx < 5 && long_str[idx] == '-') {
            sign = -1;
            idx++;
        }
        val = 0.0f;
        decimal_seen = 0;
        decimal_factor = 0.1f;
        for(; idx < 5; idx++) {
            char ch = long_str[idx];
            if(ch >= '0' && ch <= '9') {
                if(decimal_seen == 0) {
                    val = val * 10.0f + (ch - '0');
                } else {
                    val = val + (ch - '0') * decimal_factor;
                    decimal_factor *= 0.1f;
                }
            } else if(ch == '.') {
                decimal_seen = 1;
            } else {
                // ignore other chars
            }
        }
        tmp_long = sign * val;

        float diff_lat = tmp_lat - target_lat;
        float diff_long = tmp_long - target_long;
        z[i] = sqrt(diff_lat * diff_lat + diff_long * diff_long);
    }
}
